import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.BYehg5q7.js";const u=JSON.parse('{"title":"PII Obfuscation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/pii-obfuscation.md","filePath":"guide/pii-obfuscation.md","lastUpdated":1772965483000}'),s={name:"guide/pii-obfuscation.md"};function r(n,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="pii-obfuscation" tabindex="-1">PII Obfuscation <a class="header-anchor" href="#pii-obfuscation" aria-label="Permalink to &quot;PII Obfuscation&quot;">​</a></h1><p>When you import a lab PDF, getbased strips out your personal information before the text is sent to any AI provider. Your name, address, date of birth, ID numbers, and contact details are replaced with fake placeholder data. The AI only ever sees the lab results themselves.</p><h2 id="what-gets-stripped" tabindex="-1">What Gets Stripped <a class="header-anchor" href="#what-gets-stripped" aria-label="Permalink to &quot;What Gets Stripped&quot;">​</a></h2><p>The obfuscation process targets:</p><ul><li>Full name and any name-adjacent labels</li><li>Home address and postal code</li><li>Date of birth (separate from collection dates, which are preserved)</li><li>National ID numbers, social security numbers, patient IDs</li><li>Email addresses and phone numbers</li><li>US lab identifiers — Specimen ID, Accession No, Account No, MRN, Member ID</li><li>Other personally identifiable labels detected in the text</li></ul><p>Lab result lines and collection dates are specifically protected and left intact.</p><h2 id="two-obfuscation-methods" tabindex="-1">Two Obfuscation Methods <a class="header-anchor" href="#two-obfuscation-methods" aria-label="Permalink to &quot;Two Obfuscation Methods&quot;">​</a></h2><h3 id="regex-always-active" tabindex="-1">Regex (Always active) <a class="header-anchor" href="#regex-always-active" aria-label="Permalink to &quot;Regex (Always active)&quot;">​</a></h3><p>getbased always runs a rule-based scan on the PDF text. It looks for known PII patterns (label-based detection for fields like &quot;Name:&quot;, &quot;Address:&quot;, &quot;DOB:&quot;, and pattern-based detection for ID formats, emails, and phone numbers) and replaces them automatically.</p><p>The regex approach is fast and works without any local software, but may miss unusual formatting that the local AI approach would catch.</p><h3 id="local-ai-opt-in" tabindex="-1">Local AI (Opt-in) <a class="header-anchor" href="#local-ai-opt-in" aria-label="Permalink to &quot;Local AI (Opt-in)&quot;">​</a></h3><p>If you have a <a href="./ai-providers.html#local-ai-fully-local">local AI server</a> running (Ollama, LM Studio, Jan, or any OpenAI-compatible server), you can enable AI-powered PII stripping in <strong>Settings → Privacy</strong>. When enabled, a dedicated language model reads the full PDF text, identifies personal information contextually, and replaces it with realistic fake data.</p><p>This method is more accurate than regex — it catches edge cases like names embedded in unusual places — and runs entirely on your machine. Nothing is sent anywhere during the obfuscation step.</p><div class="tip custom-block"><p class="custom-block-title">Separate PII model</p><p>You can configure a separate model specifically for PII stripping in <strong>Settings → Privacy → Configure Local AI</strong>. This lets you use a small, fast model for obfuscation and a larger, more capable model for the actual lab analysis.</p></div><h2 id="review-editor" tabindex="-1">Review Editor <a class="header-anchor" href="#review-editor" aria-label="Permalink to &quot;Review Editor&quot;">​</a></h2><p>When both Local AI PII and the review editor are enabled, the review modal opens <strong>immediately</strong> when you import a PDF. The AI obfuscation streams into the right panel in real-time so you can watch the replacement happen:</p><ul><li><strong>Progress indicator</strong> — a pulsing green dot while the model loads, then a percentage counter as text streams in</li><li><strong>Word-level diffs</strong> — after streaming completes, both panels show highlighted differences: red for removed words on the left, green for added words on the right. Click the right panel to switch into edit mode</li><li><strong>Search bar</strong> — use the search field to find and verify that specific text (e.g., your name) was properly replaced</li><li><strong>Edit freely</strong> — the right panel becomes editable after streaming. The button changes to &quot;Save &amp; Send to AI&quot; when you make changes</li><li><strong>Thinking tokens</strong> — models that emit <code>&lt;think&gt;</code> tags or <code>reasoning_content</code> have their thinking stripped from the obfuscated output and shown in a collapsible section below the diff</li><li><strong>Stop</strong> — cancel the stream mid-way and edit the partial result. The model is unloaded from VRAM when you click Stop, Cancel, or &quot;Use regex instead&quot;</li><li><strong>Retry</strong> — re-run the AI obfuscation if the result looks wrong (always available after streaming completes)</li><li><strong>Use regex instead</strong> — switch to the fast rule-based method at any point</li></ul><p>Background scroll is locked while the review modal is open.</p><p>Without Local AI, the review editor shows the regex result directly for editing.</p><h2 id="configure-pii-settings" tabindex="-1">Configure PII Settings <a class="header-anchor" href="#configure-pii-settings" aria-label="Permalink to &quot;Configure PII Settings&quot;">​</a></h2><p>Open <strong>Settings → Privacy</strong> to:</p><ul><li>Toggle local AI PII obfuscation on or off</li><li>Configure the server URL and PII model</li><li>Enable the review editor to inspect and edit obfuscated text before sending</li><li>Enable debug mode to view a diff of what was replaced</li></ul><div class="tip custom-block"><p class="custom-block-title">Local AI requirements</p><p>When using the hosted app (<code>app.getbased.health</code>), the Local AI server must run on <strong>localhost</strong> — LAN servers are blocked by HTTPS mixed content rules. For Ollama, start with <code>OLLAMA_ORIGINS=* ollama serve</code> to allow cross-origin requests from the app.</p></div><div class="warning custom-block"><p class="custom-block-title">Your AI provider still receives text</p><p>Even with PII obfuscation, the anonymized lab text is sent to your configured AI provider (Anthropic, OpenRouter, or Venice) for marker extraction. The obfuscation step ensures that text contains no personal identifiers. If you want nothing sent over the network at all, use a local server as both your PII model and your main AI provider.</p></div>',24)])])}const f=t(s,[["render",r]]);export{u as __pageData,f as default};
